import{c as r,Q as a,j as e,m as l}from"./chunks/framework.BIBjCrbN.js";const b=JSON.parse('{"title":"中国科学院","description":"中国科学院自动化所/神经所/脑智卓越中心博士项目指南 — BCI与神经科学方向导师信息及申请流程","frontmatter":{"title":"中国科学院","description":"中国科学院自动化所/神经所/脑智卓越中心博士项目指南 — BCI与神经科学方向导师信息及申请流程","data-collected":"2026-05-25T00:00:00.000Z","related-directions":["bci","neuroscience","bme"],"tags":["中科院","北京","上海"],"admission-year":2027},"headers":[],"relativePath":"universities/cas.md","filePath":"universities/cas.md","lastUpdated":1780110618000}'),o={name:"universities/cas.md"};function i(n,t,d,s,h,c){return a(),e("div",null,[...t[0]||(t[0]=[l('<h1 id="中国科学院" tabindex="-1">中国科学院 <a class="header-anchor" href="#中国科学院" aria-label="Permalink to &quot;中国科学院&quot;">​</a></h1><blockquote><p><strong>最后更新</strong>: 2026年5月25日</p></blockquote><h2 id="概况" tabindex="-1">概况 <a class="header-anchor" href="#概况" aria-label="Permalink to &quot;概况&quot;">​</a></h2><p>中国科学院在神经科学和脑机接口领域拥有多个世界级研究所，其中<strong>自动化研究所</strong>（北京）以BCI和智能系统见长，<strong>脑科学与智能技术卓越创新中心/神经科学研究所</strong>（上海）以基础神经科学见长。</p><p><strong>关键区别</strong>：中科院系统的博士培养与高校有所不同——更接近&quot;师徒制&quot;导师负责制，科研氛围更偏重项目产出，且各所之间独立招生。</p><hr><h2 id="一、中国科学院自动化研究所-北京" tabindex="-1">一、中国科学院自动化研究所（北京） <a class="header-anchor" href="#一、中国科学院自动化研究所-北京" aria-label="Permalink to &quot;一、中国科学院自动化研究所（北京）&quot;">​</a></h2><h3 id="研究所概况" tabindex="-1">研究所概况 <a class="header-anchor" href="#研究所概况" aria-label="Permalink to &quot;研究所概况&quot;">​</a></h3><ul><li>官网: <a href="http://www.ia.cas.cn" target="_blank" rel="noreferrer">http://www.ia.cas.cn</a></li><li>招生页面: <a href="http://www.ia.cas.cn/yjsjy/zs/bszs/" target="_blank" rel="noreferrer">http://www.ia.cas.cn/yjsjy/zs/bszs/</a></li><li>2026年博士招生章程: <a href="http://www.ia.cas.cn/yjsjy/zs/bszs/202511/t20251104_8006012.html" target="_blank" rel="noreferrer">招生章程链接</a></li><li>招生方式: <strong>申请考核制</strong></li><li>2026年拟招收: 约 <strong>19名</strong> 全日制普通招考博士生</li></ul><h3 id="_2026年博士招生要点" tabindex="-1">2026年博士招生要点 <a class="header-anchor" href="#_2026年博士招生要点" aria-label="Permalink to &quot;2026年博士招生要点&quot;">​</a></h3><table tabindex="0"><thead><tr><th>项目</th><th>详情</th></tr></thead><tbody><tr><td>招生章程发布时间</td><td>2025年11月4日</td></tr><tr><td>报名时间</td><td>待确认（关注官网通知）</td></tr><tr><td>招生名额</td><td>约19名（自动化所17名 + 国科大AI学院2名）</td></tr><tr><td>招生方式</td><td>申请考核制</td></tr><tr><td><strong>关键要求</strong></td><td>网报前<strong>必须与拟报考导师进行充分沟通</strong></td></tr></tbody></table><blockquote><p>⚠️ 自动化所强调&quot;导师是研究生培养第一责任人&quot;，提前联系导师是必须步骤。</p></blockquote><hr><h3 id="重点课题组与导师" tabindex="-1">重点课题组与导师 <a class="header-anchor" href="#重点课题组与导师" aria-label="Permalink to &quot;重点课题组与导师&quot;">​</a></h3><h4 id="侯增广-—-研究员、博导" tabindex="-1">侯增广 — 研究员、博导 <a class="header-anchor" href="#侯增广-—-研究员、博导" aria-label="Permalink to &quot;侯增广 — 研究员、博导&quot;">​</a></h4><ul><li><strong>单位</strong>: 中国科学院自动化研究所</li><li><strong>职务</strong>: 复杂系统管理与控制国家重点实验室 <strong>副主任</strong></li><li><strong>荣誉</strong>: 国家杰出青年基金获得者、IEEE Fellow (2018)、万人计划领军人才</li><li><strong>获奖</strong>: 国家自然科学二等奖 (2017)、北京市自然科学一等奖 (2023)、国际神经网络学会丹尼斯·甘伯奖 (2023)</li></ul><p><strong>研究方向</strong>:</p><ul><li><strong>脑机接口与人机交互</strong> — 核心方向</li><li>计算智能、智能控制</li><li><strong>面向运动与认知功能障碍的康复机器人</strong></li><li>心脑血管微创介入手术机器人</li><li>嵌入式系统软硬件开发</li></ul><p><strong>招生专业</strong>: 控制理论与控制工程、模式识别与智能系统、计算机应用技术</p><p><strong>欢迎背景</strong>: 自动化、计算机、机电一体化、<strong>生物医学工程</strong> ✅</p><p><strong>2026年博士生招生</strong>: 待确认（需直接联系导师）</p><hr><h3 id="其他相关实验室-导师" tabindex="-1">其他相关实验室/导师 <a class="header-anchor" href="#其他相关实验室-导师" aria-label="Permalink to &quot;其他相关实验室/导师&quot;">​</a></h3><p>自动化所还有多个与神经工程、模式识别相关的课题组。建议访问自动化所官网「科研队伍」页面获取完整导师列表。</p><hr><h2 id="二、中国科学院脑科学与智能技术卓越创新中心-上海" tabindex="-1">二、中国科学院脑科学与智能技术卓越创新中心（上海） <a class="header-anchor" href="#二、中国科学院脑科学与智能技术卓越创新中心-上海" aria-label="Permalink to &quot;二、中国科学院脑科学与智能技术卓越创新中心（上海）&quot;">​</a></h2><h3 id="中心概况" tabindex="-1">中心概况 <a class="header-anchor" href="#中心概况" aria-label="Permalink to &quot;中心概况&quot;">​</a></h3><ul><li>又名: <strong>神经科学研究所（ION）</strong></li><li>官网: <a href="http://www.ion.ac.cn" target="_blank" rel="noreferrer">http://www.ion.ac.cn</a> / <a href="http://www.cebsit.cas.cn" target="_blank" rel="noreferrer">http://www.cebsit.cas.cn</a></li><li>招生目录: <a href="https://xn--d6q865b87npk2a" target="_blank" rel="noreferrer">2026年博士招生目录</a></li><li>位置: 上海</li></ul><h3 id="中心特色" tabindex="-1">中心特色 <a class="header-anchor" href="#中心特色" aria-label="Permalink to &quot;中心特色&quot;">​</a></h3><ul><li>蒲慕明院士领衔，中国神经科学的旗舰机构</li><li>研究涵盖分子、细胞、环路、系统、认知各层面</li><li>拥有非人灵长类研究平台</li><li>与上海科技大学、复旦大学等有联合培养</li></ul><h3 id="代表性导师-部分" tabindex="-1">代表性导师（部分） <a class="header-anchor" href="#代表性导师-部分" aria-label="Permalink to &quot;代表性导师（部分）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>导师</th><th>研究方向</th><th>说明</th></tr></thead><tbody><tr><td><strong>蒲慕明</strong></td><td>神经可塑性、轴突导向（院士）</td><td>神经科学泰斗，实验室培养了大批优秀神经科学家</td></tr><tr><td><strong>杜久林</strong></td><td>斑马鱼神经发育与行为</td><td>系统神经科学</td></tr><tr><td>多位PI</td><td>视觉、运动、学习记忆等</td><td>详见中心官网</td></tr></tbody></table><hr><h2 id="三、申请中科院的注意事项" tabindex="-1">三、申请中科院的注意事项 <a class="header-anchor" href="#三、申请中科院的注意事项" aria-label="Permalink to &quot;三、申请中科院的注意事项&quot;">​</a></h2><h3 id="与高校申请的不同" tabindex="-1">与高校申请的不同 <a class="header-anchor" href="#与高校申请的不同" aria-label="Permalink to &quot;与高校申请的不同&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方面</th><th>高校（如清华/北大）</th><th>中科院</th></tr></thead><tbody><tr><td>招生单位</td><td>学校统一招生</td><td>各研究所独立招生</td></tr><tr><td>导师权力</td><td>导师在委员会中有发言权</td><td>导师决定权更大</td></tr><tr><td>科研氛围</td><td>偏学术+教学</td><td>偏科研项目产出</td></tr><tr><td>培养模式</td><td>有课程学习阶段</td><td>更多时间在实验室</td></tr><tr><td>生活待遇</td><td>学校奖学金+导师津贴</td><td>研究所统一待遇（通常较高）</td></tr><tr><td>学位授予</td><td>学校授予</td><td>中国科学院大学授予</td></tr></tbody></table><h3 id="申请建议" tabindex="-1">申请建议 <a class="header-anchor" href="#申请建议" aria-label="Permalink to &quot;申请建议&quot;">​</a></h3><ol><li><strong>提前联系导师是硬性要求</strong>（自动化所明确写明）</li><li><strong>各所独立报名</strong>：可以同时申请自动化所和神经所，互不影响</li><li><strong>竞争激烈但待遇好</strong>：中科院博士生月收入通常高于高校</li><li><strong>住宿条件</strong>：自动化所（北京）和神经所（上海）通常提供所内宿舍</li></ol><hr><h2 id="针对你的申请建议" tabindex="-1">针对你的申请建议 <a class="header-anchor" href="#针对你的申请建议" aria-label="Permalink to &quot;针对你的申请建议&quot;">​</a></h2><ol><li><strong>侯增广课题组高度匹配</strong>：BCI+康复机器人+生物医学工程背景直接对口，你的EMG反馈系统和神经技术背景可以作为切入点</li><li><strong>自动化所报名前必须联系导师</strong>：建议2025年7-8月发送联系邮件</li><li><strong>神经所（上海）适合偏基础神经科学方向</strong>：如果你倾向于神经发育/类器官方向，神经所的基础研究平台更合适</li><li><strong>同时申请多所不冲突</strong>：中科院系统内各所独立招生，建议同时申请自动化所（BCI应用）和神经所（基础神经科学）以扩大机会</li></ol><hr><h2 id="信息来源" tabindex="-1">信息来源 <a class="header-anchor" href="#信息来源" aria-label="Permalink to &quot;信息来源&quot;">​</a></h2><ul><li><a href="http://www.ia.cas.cn/yjsjy/zs/bszs/202511/t20251104_8006012.html" target="_blank" rel="noreferrer">自动化所2026博士招生章程</a>（访问日期: 2026-05-25）</li><li><a href="http://www.ia.cas.cn" target="_blank" rel="noreferrer">自动化所官网</a>（访问日期: 2026-05-25）</li><li><a href="http://www.cebsit.cas.cn" target="_blank" rel="noreferrer">脑智卓越中心</a>（访问日期: 2026-05-25）</li></ul><hr><p><em>本页面信息采集于2026年5月，请以中国科学院各研究所官网最新公告为准。</em></p><p><em>下次更新建议: 2026年8月</em></p>',47)])])}const u=r(o,[["render",i]]);export{b as __pageData,u as default};
